1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  items: Item[];
14	}
15	
16	export interface QuoteResult {
17	  premium: number;
18	}
19	
20	const BASE_PREMIUMS: Record<string, number> = {
21	  sword: 100,
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	};
26	const PROCESSING_FEE = 5;
27	
28	// First-insurance surcharge of +10%, expressed as a numerator/denominator pair
29	// so the maths stays in integers: `base * 110 / 100` avoids the float error of
30	// `base * 1.1` (e.g. 100 * 1.1 === 100.00000000000001).
31	const FIRST_INSURANCE_SURCHARGE_NUMERATOR = 110;
32	const FIRST_INSURANCE_SURCHARGE_DENOMINATOR = 100;
33	
34	const sumBasePremiums = (items: Item[]): number =>
35	  items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
36	
37	export const quote = (
38	  _customer: Customer,
39	  step: QuoteStep,
40	  _quoteIndex: number,
41	): QuoteResult => {
42	  const basePremium = sumBasePremiums(step.items);
43	  const withFirstInsurance =
44	    (basePremium * FIRST_INSURANCE_SURCHARGE_NUMERATOR) /
45	    FIRST_INSURANCE_SURCHARGE_DENOMINATOR;
46	  const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
47	  return { premium };
48	};
